  "inlineSchema": "// ============================================================\n// Personal Calendar Manager — Prisma Schema (v2)\n// Database: PostgreSQL\n// ============================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ============================================================\n// ENUMS\n// ============================================================\n\n/// Controls who can see an event\nenum Visibility {\n  private\n  invited_only\n  public\n}\n\n/// Colour-coding category for an event\nenum EventType {\n  work\n  personal\n  family\n  health\n  social\n  other\n}\n\n/// Only stored status — upcoming/completed are derived at query time\nenum EventStatus {\n  active\n  cancelled\n}\n\n/// How the reminder should be delivered\nenum ReminderMethod {\n  browser\n  email\n  both\n}\n\n/// How often the event repeats\nenum RecurrenceType {\n  none\n  daily\n  weekly\n  monthly\n}\n\n/// Whether a user has responded to an invitation\nenum InvitationStatus {\n  pending\n  accepted\n  declined\n}\n\n/// Delivery state of a single reminder log entry\nenum DeliveryStatus {\n  pending\n  sent\n  failed\n}\n\n// ============================================================\n// MODELS\n// ============================================================\n\n/// Registered users — owns events and receives invitations/reminders\nmodel User {\n  id           String   @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  name         String   @db.VarChar(100)\n  email        String   @unique @db.VarChar(255)\n  passwordHash String   @map(\"password_hash\") @db.VarChar(255)\n  createdAt    DateTime @default(now()) @map(\"created_at\")\n\n  // Relations\n  events       Event[]       @relation(\"EventOwner\")\n  invitations  Invitation[]  @relation(\"InvitedUser\")\n  reminderLogs ReminderLog[] @relation(\"ReminderRecipient\")\n\n  @@map(\"users\")\n}\n\n/// Calendar events — series-level row; occurrences are expanded virtually at read time\nmodel Event {\n  id                    String          @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  createdBy             String          @map(\"created_by\") @db.Uuid\n  title                 String          @db.VarChar(255)\n  description           String?         @db.Text\n  location              String?         @db.VarChar(255)\n  startDatetime         DateTime        @map(\"start_datetime\") @db.Timestamptz()\n  endDatetime           DateTime        @map(\"end_datetime\") @db.Timestamptz()\n  allDay                Boolean         @default(false) @map(\"all_day\")\n  visibility            Visibility      @default(private)\n  eventType             EventType       @map(\"event_type\")\n  reminderMinutesBefore Int?            @map(\"reminder_minutes_before\")\n  reminderMethod        ReminderMethod? @map(\"reminder_method\")\n  timezone              String          @db.VarChar(64)\n  recurrenceType        RecurrenceType  @default(none) @map(\"recurrence_type\")\n  repeatUntil           DateTime?       @map(\"repeat_until\") @db.Date\n  status                EventStatus     @default(active)\n  createdAt             DateTime        @default(now()) @map(\"created_at\")\n  updatedAt             DateTime        @updatedAt @map(\"updated_at\")\n\n  // Relations\n  owner        User          @relation(\"EventOwner\", fields: [createdBy], references: [id], onDelete: Cascade)\n  invitations  Invitation[]  @relation(\"EventInvitations\")\n  reminderLogs ReminderLog[] @relation(\"EventReminderLogs\")\n\n  // Indexes\n  @@index([createdBy])\n  @@index([startDatetime, endDatetime])\n  @@index([status])\n  @@map(\"events\")\n}\n\n/// Tracks which users have been invited to which events and their response\nmodel Invitation {\n  id               String           @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  eventId          String           @map(\"event_id\") @db.Uuid\n  invitedUserId    String           @map(\"invited_user_id\") @db.Uuid\n  invitationStatus InvitationStatus @default(pending) @map(\"invitation_status\")\n  invitedAt        DateTime         @default(now()) @map(\"invited_at\")\n\n  // Relations\n  event       Event @relation(\"EventInvitations\", fields: [eventId], references: [id], onDelete: Cascade)\n  invitedUser User  @relation(\"InvitedUser\", fields: [invitedUserId], references: [id], onDelete: Cascade)\n\n  // A user can only be invited once per event\n  @@unique([eventId, invitedUserId])\n  // Indexes\n  @@index([invitedUserId])\n  @@index([eventId])\n  @@map(\"invitations\")\n}\n\n/// Tracks individual reminder delivery attempts per user per occurrence\n/// Needed to: (1) avoid duplicate sends on recurring events, (2) track per-recipient state\nmodel ReminderLog {\n  id                 String         @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  eventId            String         @map(\"event_id\") @db.Uuid\n  userId             String         @map(\"user_id\") @db.Uuid\n  /// Which specific occurrence this reminder belongs to (= startDatetime for non-recurring events)\n  occurrenceDatetime DateTime       @map(\"occurrence_datetime\") @db.Timestamptz()\n  /// Snapshot of reminder_method at schedule time — insulates log from future event edits\n  method             ReminderMethod\n  /// = occurrence_datetime - reminder_minutes_before; what the cron job polls on\n  scheduledFor       DateTime       @map(\"scheduled_for\") @db.Timestamptz()\n  deliveryStatus     DeliveryStatus @default(pending) @map(\"delivery_status\")\n  sentAt             DateTime?      @map(\"sent_at\")\n  createdAt          DateTime       @default(now()) @map(\"created_at\")\n\n  // Relations\n  event Event @relation(\"EventReminderLogs\", fields: [eventId], references: [id], onDelete: Cascade)\n  user  User  @relation(\"ReminderRecipient\", fields: [userId], references: [id], onDelete: Cascade)\n\n  // Prevent duplicate sends for the same user/occurrence/method combination\n  @@unique([eventId, userId, occurrenceDatetime, method])\n  // Primary query pattern for the cron worker: \"what reminders are due right now?\"\n  @@index([scheduledFor, deliveryStatus])\n  @@map(\"reminder_logs\")\n}\n",
